mapper.update:
UPDATE er.tn_cef
   SET last_chg_dt      = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE cef_id    = #{cefId}
   AND cef_st_cd = 'DRAFT'
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE er.tn_cef
   SET ttl_redu_amt     = #{ttlReduAmt},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE cef_id = #{cefId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE er.tn_cef
   SET cef_st_cd        = #{newSt},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE cef_id = #{cefId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
